import {SpotterMainApp} from "../type";

export * from './consoleProxy'

export type LogSystemOptions = Logger | {
    prefix: string
}
export class Logger {
    prefix = ''
    constructor(prefix: LogSystemOptions['prefix']) {
        this.prefix = `[${prefix}]`
    }

    log = console.log.bind(console, this.prefix)
    info = console.log.bind(console, this.prefix)
    warn = console.warn.bind(console, this.prefix)
    error = console.error.bind(console, this.prefix)
}





export function boostrapLogSystem(options: LogSystemOptions, sptApp: SpotterMainApp) {
    sptApp.log = {} as any
    sptApp.log.logger = options instanceof Logger ? options : new Logger(options.prefix)
}


